import collections

class RecentCounter:

    def __init__(self):
        self.q = collections.deque()
        self.window_size = 3000 # milliseconds

    def ping(self, t: int) -> int:
        self.q.append(t)

        while self.q and self.q[0] < t - self.window_size:
            self.q.popleft()

        return len(self.q)
